var sfGroup singleflight.Group

func GetUser(ctx context.Context, id string) (*User, error) {
    cached, err := rdb.Get(ctx, "user:"+id).Bytes()
    if err == nil {
        if string(cached) == "__NULL__" { return nil, ErrNotFound }
        var u User
        json.Unmarshal(cached, &u)
        return &u, nil
    }
    if err != redis.Nil {
        // Redis error: degrade to DB
        return db.QueryUser(ctx, id)
    }
    val, err, _ := sfGroup.Do("user:"+id, func() (interface{}, error) {
        u, err := db.QueryUser(ctx, id)
        if err == sql.ErrNoRows {
            rdb.Set(ctx, "user:"+id, "__NULL__", 60*time.Second)
            return nil, ErrNotFound
        }
        ttl := 30*time.Minute + time.Duration(rand.Intn(300))*time.Second
        rdb.Set(ctx, "user:"+id, marshal(u), ttl)
        return u, nil
    })
    return val.(*User), err
}
